import React, { useState, useEffect } from 'react';
import Modal from '../components/Modal';
import api from '../services/api';

const LoanApprovals = () => {
  const [loans, setLoans] = useState([]);
  const [selected, setSelected] = useState(null);
  const [remarks, setRemarks] = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchLoans();
  }, []);

  const fetchLoans = async () => {
    try {
      const res = await api.get('/admin/loans/pending');
      setLoans(res.data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const approve = async (id) => {
    try {
      await api.post(`/admin/loan/${id}/approve`);
      setLoans(l => l.filter(x => x._id !== id));
      setSelected(null);
    } catch (err) {
      alert('Failed to approve loan');
    }
  }
  const reject = async (id) => {
    try {
      await api.post(`/admin/loan/${id}/reject`);
      setLoans(l => l.filter(x => x._id !== id));
      setSelected(null);
    } catch (err) {
      alert('Failed to reject loan');
    }
  }

  return (
    <div className="fade-in">
      <div className="flex-between mb-6">
        <h2 className="page-title">Loan Approvals</h2>
        <div className="card" style={{ padding: '8px 16px' }}>
          <span style={{ fontWeight: '500', color: 'var(--text-secondary)' }}>Pending Requests: <span style={{ color: 'var(--warning)' }}>{loans.length}</span></span>
        </div>
      </div>

      <div className="card" style={{ padding: '0', overflow: 'hidden', borderRadius: '12px', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)' }}>
        {loading ? <div style={{ padding: 24, textAlign: 'center' }}>Loading pending loans...</div> : (
          <table style={{ width: '100%', borderCollapse: 'collapse' }}>
            <thead style={{ background: '#f9fafb', borderBottom: '1px solid #e5e7eb' }}>
              <tr>
                <th style={{ padding: '12px 24px', textAlign: 'left', fontSize: '12px', fontWeight: '600', color: '#6b7280', textTransform: 'uppercase' }}>Member ID</th>
                <th style={{ padding: '12px 24px', textAlign: 'left', fontSize: '12px', fontWeight: '600', color: '#6b7280', textTransform: 'uppercase' }}>Amount</th>
                <th style={{ padding: '12px 24px', textAlign: 'left', fontSize: '12px', fontWeight: '600', color: '#6b7280', textTransform: 'uppercase' }}>Purpose</th>
                <th style={{ padding: '12px 24px', textAlign: 'left', fontSize: '12px', fontWeight: '600', color: '#6b7280', textTransform: 'uppercase' }}>Date</th>
                <th style={{ padding: '12px 24px', textAlign: 'left', fontSize: '12px', fontWeight: '600', color: '#6b7280', textTransform: 'uppercase' }}>Status</th>
                <th style={{ padding: '12px 24px', textAlign: 'left', fontSize: '12px', fontWeight: '600', color: '#6b7280', textTransform: 'uppercase' }}>Actions</th>
              </tr>
            </thead>
            <tbody>
              {loans.map(l => (
                <tr key={l._id} style={{ borderBottom: '1px solid #f3f4f6' }}>
                  <td style={{ padding: '16px 24px', color: '#111827' }}>{l.memberId}</td>
                  <td style={{ padding: '16px 24px', fontWeight: '500', color: '#10b981' }}>{l.amount.toLocaleString()} ETB</td>
                  <td style={{ padding: '16px 24px', color: '#374151' }}>{l.purpose}</td>
                  <td style={{ padding: '16px 24px', color: '#6b7280' }}>{new Date(l.createdAt).toLocaleDateString()}</td>
                  <td style={{ padding: '16px 24px' }}>
                    <span style={{ padding: '4px 12px', borderRadius: '9999px', fontSize: '12px', fontWeight: '500', background: '#fef3c7', color: '#d97706' }}>
                      {l.status}
                    </span>
                  </td>
                  <td style={{ padding: '16px 24px' }}>
                    <button className="btn secondary" onClick={() => setSelected(l)} style={{ padding: '6px 12px', fontSize: '13px' }}>Review</button>
                  </td>
                </tr>
              ))}
              {loans.length === 0 && <tr><td colSpan="6" style={{ padding: '40px', textAlign: 'center', color: '#6b7280' }}>No pending loans found.</td></tr>}
            </tbody>
          </table>
        )}
      </div>

      {selected && (
        <Modal title={`Review Loan Application`} onClose={() => setSelected(null)}>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px', marginBottom: '24px' }}>
            <div>
              <label style={{ fontSize: '12px', color: '#6b7280', display: 'block', marginBottom: '4px' }}>Amount Requested</label>
              <div style={{ fontSize: '18px', fontWeight: 'bold', color: '#10b981' }}>{selected.amount.toLocaleString()} ETB</div>
            </div>
            <div>
              <label style={{ fontSize: '12px', color: '#6b7280', display: 'block', marginBottom: '4px' }}>Member ID</label>
              <div style={{ fontSize: '16px', fontWeight: '500' }}>{selected.memberId}</div>
            </div>
            <div style={{ gridColumn: 'span 2' }}>
              <label style={{ fontSize: '12px', color: '#6b7280', display: 'block', marginBottom: '4px' }}>Purpose</label>
              <div style={{ fontSize: '14px', color: '#374151', background: '#f9fafb', padding: '12px', borderRadius: '6px' }}>{selected.purpose}</div>
            </div>
          </div>

          <div style={{ marginBottom: 24 }}>
            <label style={{ fontSize: '14px', fontWeight: '500', display: 'block', marginBottom: '8px' }}>Admin Remarks</label>
            <textarea
              className="input"
              value={remarks}
              onChange={e => setRemarks(e.target.value)}
              placeholder="Enter reason for approval or rejection..."
              style={{ height: 100, width: '100%', padding: '12px', borderRadius: '6px', border: '1px solid #d1d5db' }}
            />
          </div>

          <div style={{ display: 'flex', gap: 12, justifyContent: 'flex-end' }}>
            <button className="btn secondary" onClick={() => { reject(selected._id); }} style={{ background: '#fee2e2', color: '#ef4444', border: 'none' }}>Reject Application</button>
            <button className="btn" onClick={() => { approve(selected._id); }} style={{ background: '#10b981', color: '#fff', border: 'none' }}>Approve Application</button>
          </div>
        </Modal>
      )}

    </div>
  );
}
export default LoanApprovals;
